+    encoding: "utf8",
+    env: env ? { ...process.env, ...env } : process.env,
+  }).trim();
 };

 describe("git-hooks/pre-commit (integration)", () => {
@@ -33,6 +37,12 @@ describe("git-hooks/pre-commit (integration)", () => {
       "process.exit(0);\n",
